sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    var plugDetails = new GlideAjax('AJAXUtils');
	plugDetails.addParam('sysparm_name', 'getPlugData');
	// 'sys_id' is the parameter name
    plugDetails.addParam('sysparm_sys_id', g_form.getValue('u_plug_type'));
    plugDetails.getXMLAnswer(updatePlugSection);

    g_form.addInfoMessage('Passed Plug Sys_id: ' + g_form.getValue('u_plug_type'));

    function updatePlugSection(response) {
        g_form.addInfoMessage('Response: ' + response);
        if (response) {
            var parsedData = JSON.parse(response);
            g_form.setValue('u_si_box', parsedData.supply_input);
        } else {
            g_form.addInfoMessage('No response parsing');
        }
    }
}
